#include <stdio.h>
#include <stdlib.h>

// Function to calculate the Nim-sum
long long nim_sum(long long* piles, int n) {
    long long sum = 0;
    for (int i = 0; i < n; i++) {
        sum ^= piles[i];
    }
    return sum;
}

// Function to generate permutations
void generate_permutations(long long* piles, int n, int start, long long* count) {
    if (start == n) {
        if (nim_sum(piles, n) != 0) {
            (*count)++;
        }
    } else {
        for (int i = start; i < n; i++) {
            long long temp = piles[start];
            piles[start] = piles[i];
            piles[i] = temp;
            generate_permutations(piles, n, start + 1, count);
            temp = piles[start];
            piles[start] = piles[i];
            piles[i] = temp;
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        long long piles[n];
        for (int i = 0; i < n; i++) {
            scanf("%lld", &piles[i]);
        }
        long long count = 0;
        generate_permutations(piles, n, 0, &count);
        printf("%lld\n", count % (1000000007));
    }
    return 0;
}

