import java.util.Scanner;
public class Main {
    // Function to calculate the Nim-sum
    public static long nim_sum(long[] piles) {
        long sum = 0;
        for (long pile : piles) {
            sum ^= pile;
        }
        return sum;
    }

    // Function to generate permutations
    public static void generate_permutations(long[] piles, int start, long[] count) {
        if (start == piles.length) {
            if (nim_sum(piles) != 0) {
                count[0]++;
            }
        } else {
            for (int i = start; i < piles.length; i++) {
                long temp = piles[start];
                piles[start] = piles[i];
                piles[i] = temp;
                generate_permutations(piles, start + 1, count);
                temp = piles[start];
                piles[start] = piles[i];
                piles[i] = temp;
            }
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            long[] piles = new long[n];
            for (int i = 0; i < n; i++) {
                piles[i] = scanner.nextLong();
            }
            long[] count = new long[] {0};
            generate_permutations(piles, 0, count);
            System.out.println(count[0] % (1000000007));
        }
    }
}

